import threading
import time
import socket
import re
import subprocess
import time
import traceback
import platform


def ping(ip, time_out=15, log_handle=None):
    __ping_result = False

    def __log(msg):
        if log_handle:
            log_handle(msg)

    try:
        # TODO support mac
        os_name = platform.system()
        cmd = ['ping', ip, '-t'] if os_name == "Windows" else ['ping', ip]
        search_match = '.*TTL=(\d+)' if os_name == "Windows" else '.*ttl=(\d+)'
        p = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        start_time = time.time()
        while True:
            result = str(p.stdout.readline())
            # TODO remove print
            # print('result:{}'.format(result))
            __log('ping:[{}], result:{}'.format(ip, result))
            result = re.search(search_match, result)
            if result and len(result.groups()) > 0:
                result = result.groups()
                __log('ping:[{}], groups.result:{}'.format(ip, result))
                __ping_result = True
                break

            if time.time() - start_time > time_out:
                __log('ping:[{}], timeout:{}'.format(ip, time.time() - start_time))
                __ping_result = False
    except Exception as e:
        __log('ping:[{}], exception:{}'.format(ip, str(e)))
        print(traceback.format_exc())
    finally:
        p.kill()

    return __ping_result


class TcpClient(object):
    SIZE = 2048

    def __init__(self, ip, port, publisher):
        self._net_config = (ip, port)
        self.publisher = publisher
        self.__socket = None
        #self.ping_cobo()
        self.ping_cobo_status = False

    def ping_cobo(self):
        if not ping(self._net_config[0], time_out=110):
            # self.write_file_log('ping cobo fail')
            return False
        self.ping_cobo_status = True
        return True

    def get_net_config(self):
        return self._net_config

    def log(self, msg):
        if self.publisher:
            self.publisher.publish(str(msg))

    def connect(self):

        try:
            if not self.__socket:
                self.__socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                self.__socket.setsockopt(socket.SOL_SOCKET, socket.SO_KEEPALIVE, 1)
                self.__socket.settimeout(8)

            self.__socket.connect(self._net_config)

            # self.log("TcpClient CONNECT SUCCESS!! ")

            return True
        except Exception as e:
            self.log("TcpClient CONNECT Exception type:{} e:{}".format(type(e), str(e)))
            return False

    def shutdown(self):
        if self.__socket:
            self.__socket.close()
            # self.log("TcpClient shutdown CLOSED SUCCESS!!")
            del self.__socket
            self.__socket = None

    def send(self, cmd):
        try:

            cmd = cmd.encode()
            self.__socket.send(cmd)

            return True
        except ConnectionResetError as e:
            self.log("TcpClient ConnectionResetError e:{}".format(str(e)))
        except Exception as e:
            self.log("TcpClient send-exception type:{} e:{}".format(type(e), str(e)))

    def read(self, size=1024):
        try:
            line = self.__socket.recv(size)
        except socket.timeout:
            line = None
        return line

    def read_until(self, terminator="\r\n"):
        line = str()
        while True:
            try:
                c = self.__socket.recv(self.SIZE).decode()
                if c:
                    line += c
                    if line.rfind(terminator) > 0:
                        break
            except socket.timeout:
                timeout_happen = True
                self.log('readUntil socket.timeout')
                break
        return line

    def send_read(self, cmd, terminator="\r\n"):

        reply = None
        try:

            if not self.connect():
                return False

            # self.log("req:  {}".format(cmd))
            self.send(cmd + terminator)
            reply = self.read_until(terminator)
            # self.log("rep:  {}".format(reply))
        except Exception as e:
            self.log('send_read exception:{}'.format(str(e)))
        finally:
            self.shutdown()

        return reply


